esqlQuery.esql:
FROM metrics-redisenterprise.otel-default
| WHERE redis_up IS NOT NULL
| STATS min_up = MIN(redis_up) BY redis, bdb, node, role, cluster
// Alert when any shard reports as down (redis_up < 1)
// A primary shard going down triggers automatic failover to its replica
// A replica going down reduces redundancy — the database continues but is less resilient
| WHERE min_up < 1
